let itemsOutput = [];

for (const item of items) {

  const rawJid = item.json.data?.event?.Join?.[0];
  let numeroTratado = null;

  if (typeof rawJid === 'string') {

    // 1. Limpeza inicial
    let tempNum = rawJid.split('@')[0].replace(/\D/g, '');
    let len = tempNum.length;

    /* --- LÓGICA DE REMOÇÃO DO 9 (Sua lógica original) --- */
    if (len === 13 && tempNum[4] === '9') {
      tempNum = tempNum.substring(0, 4) + tempNum.substring(5);
    }
    else if (len === 11 && tempNum[2] === '9') {
      tempNum = tempNum.substring(0, 2) + tempNum.substring(3);
    }

    /* --- NOVA LÓGICA: INSERÇÃO DO 9 ADICIONAL --- */
    // Atualizamos o tamanho após a limpeza
    len = tempNum.length;

    // Se o número tem 12 dígitos (Ex: 551188887777), inserimos o '9' na posição 4
    // O resultado será: 5511 9 88887777 (13 dígitos)
    if (len === 12 && tempNum.startsWith('55')) {
      tempNum = tempNum.substring(0, 4) + '9' + tempNum.substring(4);
    }
    // Se o número tem 10 dígitos (Ex: 1188887777), inserimos o '9' na posição 2
    else if (len === 10) {
      tempNum = tempNum.substring(0, 2) + '9' + tempNum.substring(2);
    }

    numeroTratado = tempNum;
  }

  // 4. Adiciona o campo 'phone_number_clean' ao JSON original
  itemsOutput.push({
    json: {
      ...item.json,
      phone_number_clean: numeroTratado
    }
  });
}

return itemsOutput;

// 1. Tags que você deseja adicionar (se não existirem)
const tagsParaAdicionar = "comunidade-aplic";

// 2. Tags que você deseja remover (se existirem)
// Deixe vazio ("") ou liste as tags separadas por vírgula.
const tagsParaRemover = "1-lead-novo";

// 3. Pega o array de tags do nó anterior "Get Tags" (usando sintaxe V1)
// Se não houver tags existentes, será um array vazio ([]).
const tagsExistentes = $('Get Tags1').first().json.payload || [];


// --- Processamento ---

// 4. Cria um Set de todas as tags que DEVERÃO PERMANECER ou SER ADICIONADAS
const setDeTagsFinais = new Set();

// 5. Converte a string de tags a serem removidas para um Set para pesquisa rápida
const setDeTagsParaRemover = new Set(
    tagsParaRemover.split(',').map(tag => tag.trim()).filter(tag => tag.length > 0)
);

// 6. Adiciona ao SetFinais as tags EXISTENTES que NÃO DEVEM ser removidas
tagsExistentes.forEach(tag => {
    // Adiciona a tag existente APENAS se ela NÃO estiver na lista de remoção
    if (!setDeTagsParaRemover.has(tag)) {
        setDeTagsFinais.add(tag);
    }
});

// 7. Adiciona as tags NOVAS/DESEJADAS ao SetFinais (o Set ignora duplicatas automaticamente)
const tagsNovas = tagsParaAdicionar.split(',').map(tag => tag.trim());
tagsNovas.forEach(tag => {
    // Adiciona a tag APENAS se ela NÃO estiver na lista de remoção (para garantir)
    if (!setDeTagsParaRemover.has(tag)) {
        setDeTagsFinais.add(tag);
    }
});


// --- Saída ---

// 8. Converte o Set de volta para um Array
const tagsArray = Array.from(setDeTagsFinais);

// 9. Mapeia o array para adicionar as aspas em cada tag e junta em uma string.
const tagsAtualizadasString = tagsArray
    .map(tag => `"${tag}"`) // Adiciona aspas (ex: "tag_a")
    .join(','); // Junta as tags com vírgula (ex: "tag_a","tag_b")

// 10. Retorna o resultado no formato de string
return [{
    json: {
        // Retorna a lista de tags atualizadas no formato "tag1","tag2"
        tagsAtualizadas: tagsAtualizadasString,
    }
}];

// Nó: "Buscar Contato Chatwoot - Telefone + Meta + Sorteio"

// ========================================
// 1. CONFIGURAÇÃO E SORTEIO
// ========================================
const CHATWOOT_CONFIG = {
  url: 'https://chat.aplicgo.com',
  accountId: '1',
  apiKey: 'fmURrfLvWrJbtkAu6RUtQLYn',
  retryDelay: 600
};

// Sorteio aleatório de agentes (IDs: 10, 9 ou 6)
const agentes = [10, 9, 6];
const agenteSorteado = agentes[Math.floor(Math.random() * agentes.length)];

// ========================================
// 2. RECUPERAÇÃO DE DADOS
// ========================================
let phoneInput = null;
try {
  // Busca direta do nó anterior
  phoneInput = $input.first().json['numero limpo'];
} catch (error) {
  phoneInput = null;
}

if (!phoneInput) {
  throw new Error('❌ Não foi possível recuperar o número de telefone no nó "Edit Fields2"');
}

// ========================================
// 3. FUNÇÃO DE BUSCA (EXTRAÇÃO DE META)
// ========================================
async function buscarContato(query, tipo) {
  if (!query) return null;
  try {
    const options = {
      method: 'GET',
      url: `${CHATWOOT_CONFIG.url}/api/v1/accounts/${CHATWOOT_CONFIG.accountId}/contacts/search`,
      qs: { q: query },
      headers: {
        'api_access_token': CHATWOOT_CONFIG.apiKey,
        'Content-Type': 'application/json'
      },
      json: true
    };

    const response = await this.helpers.httpRequest(options);

    return {
      contato: (response.payload && response.payload.length > 0) ? response.payload[0] : null,
      meta: response.meta || { count: 0 }
    };
  } catch (error) {
    return { contato: null, meta: { count: 0 } };
  }
}

// ========================================
// 4. PREPARAÇÃO DAS VARIAÇÕES DE TELEFONE
// ========================================
const telefone = phoneInput.toString().replace(/\D/g, '');
const variacoesTelefone = [{ query: telefone, tipo: 'telefone_completo' }];

if (telefone.startsWith('55')) {
  if (telefone.length > 11) {
    variacoesTelefone.push({ query: telefone.slice(2), tipo: 'telefone_sem_55' });
  }
  if (telefone.length === 13 && telefone[4] === '9') {
    variacoesTelefone.push({ 
      query: telefone.substring(2, 4) + telefone.substring(5), 
      tipo: 'telefone_sem_9_legacy' 
    });
  }
}

// ========================================
// 5. EXECUÇÃO DA BUSCA
// ========================================
let contatoEncontrado = null;
let metaFinal = { count: 0 };
let encontradoPor = null;

for (let i = 0; i < variacoesTelefone.length; i++) {
  const resultado = await buscarContato.call(this, variacoesTelefone[i].query, variacoesTelefone[i].tipo);

  if (resultado.contato) {
    contatoEncontrado = resultado.contato;
    metaFinal = resultado.meta;
    encontradoPor = variacoesTelefone[i].tipo;
    break;
  }

  if (i < variacoesTelefone.length - 1) {
    await new Promise(r => setTimeout(r, CHATWOOT_CONFIG.retryDelay));
  }
}

// ========================================
// 6. RETORNO FINAL PARA O n8n
// ========================================
return [{
  json: {
    encontrado: !!contatoEncontrado,
    count: metaFinal.count, // Facilita o uso no Switch logo após este nó
    meta: metaFinal,

    // Agente sorteado para atribuição
    agente_sorteado_id: agenteSorteado,

    // Dados do Contato
    id: contatoEncontrado?.id || null,
    name: contatoEncontrado?.name || null,
    phone_number: contatoEncontrado?.phone_number || null,
    encontrado_por: encontradoPor,
    input_phone: phoneInput,
    payload_completo: contatoEncontrado
  }
}];

const tags = $('Get Tags1').first().json.payload || [];

// Se ainda não tem a tag comunidade-aplic, é a primeira vez
const primeiraVez = !tags.includes('comunidade-aplic');

return [{
  json: {
    primeira_vez: primeiraVez,
    tags_atuais: tags
  }
}];

