        tagsAtualizadas: tagsAtualizadasString,
    }
}];

// Nó: "Buscar Contato Chatwoot - Telefone + Meta + Sorteio"

// ========================================
// 1. CONFIGURAÇÃO E SORTEIO
// ========================================
const CHATWOOT_CONFIG = {
  url: 'https://chat.aplicgo.com',
  accountId: '1',
  apiKey: 'fmURrfLvWrJbtkAu6RUtQLYn',
  retryDelay: 600
};

// Sorteio aleatório de agentes (IDs: 10, 9 ou 6)
const agentes = [10, 9, 6];
const agenteSorteado = agentes[Math.floor(Math.random() * agentes.length)];

// ========================================
// 2. RECUPERAÇÃO DE DADOS
// ========================================
let phoneInput = null;
try {
  // Busca direta do nó anterior
  phoneInput = $input.first().json['numero limpo'];
} catch (error) {
  phoneInput = null;
}

if (!phoneInput) {
  throw new Error('❌ Não foi possível recuperar o número de telefone no nó "Edit Fields2"');
}

// ========================================
// 3. FUNÇÃO DE BUSCA (EXTRAÇÃO DE META)
// ========================================
async function buscarContato(query, tipo) {
  if (!query) return null;
  try {
    const options = {
      method: 'GET',
      url: `${CHATWOOT_CONFIG.url}/api/v1/accounts/${CHATWOOT_CONFIG.accountId}/contacts/search`,
      qs: { q: query },
      headers: {
        'api_access_token': CHATWOOT_CONFIG.apiKey,
        'Content-Type': 'application/json'
      },
      json: true
    };

    const response = await this.helpers.httpRequest(options);

    return {
      contato: (response.payload && response.payload.length > 0) ? response.payload[0] : null,
      meta: response.meta || { count: 0 }
    };
  } catch (error) {
    return { contato: null, meta: { count: 0 } };
  }
}

// ========================================
// 4. PREPARAÇÃO DAS VARIAÇÕES DE TELEFONE
// ========================================
const telefone = phoneInput.toString().replace(/\D/g, '');
const variacoesTelefone = [{ query: telefone, tipo: 'telefone_completo' }];

if (telefone.startsWith('55')) {
  if (telefone.length > 11) {
    variacoesTelefone.push({ query: telefone.slice(2), tipo: 'telefone_sem_55' });
  }
  if (telefone.length === 13 && telefone[4] === '9') {
    variacoesTelefone.push({ 
      query: telefone.substring(2, 4) + telefone.substring(5), 
      tipo: 'telefone_sem_9_legacy' 
    });
  }
}

// ========================================
// 5. EXECUÇÃO DA BUSCA
// ========================================
let contatoEncontrado = null;
let metaFinal = { count: 0 };
let encontradoPor = null;

for (let i = 0; i < variacoesTelefone.length; i++) {
  const resultado = await buscarContato.call(this, variacoesTelefone[i].query, variacoesTelefone[i].tipo);

  if (resultado.contato) {
    contatoEncontrado = resultado.contato;
    metaFinal = resultado.meta;
    encontradoPor = variacoesTelefone[i].tipo;
    break;
  }

  if (i < variacoesTelefone.length - 1) {
    await new Promise(r => setTimeout(r, CHATWOOT_CONFIG.retryDelay));
  }
}

// ========================================
// 6. RETORNO FINAL PARA O n8n
// ========================================
return [{
  json: {
    encontrado: !!contatoEncontrado,
    count: metaFinal.count, // Facilita o uso no Switch logo após este nó
    meta: metaFinal,

    // Agente sorteado para atribuição
    agente_sorteado_id: agenteSorteado,

    // Dados do Contato
    id: contatoEncontrado?.id || null,
    name: contatoEncontrado?.name || null,
    phone_number: contatoEncontrado?.phone_number || null,
    encontrado_por: encontradoPor,
    input_phone: phoneInput,
    payload_completo: contatoEncontrado
  }
}];

const tags = $('Get Tags1').first().json.payload || [];

// Se ainda não tem a tag comunidade-aplic, é a primeira vez
const primeiraVez = !tags.includes('comunidade-aplic');

return [{
  json: {
    primeira_vez: primeiraVez,
    tags_atuais: tags
  }
}];

